#include<bits/stdc++.h>
using namespace std;
int t[500010][2],cnt[500010],cnt1[500010],id;
int s[500010];
void insert(int s[],int len)
{
    int p=0;
    for(int i=1;i<=len;i++)
    {
        int c=s[i];
        if(!t[p][c])
        {
            t[p][c]=++id;
        }
        p=t[p][c];
        cnt[p]++;
    }
    cnt1[p]++;
}
int query(int s[],int len)
{
    int ans=0,p=0;
    for(int i=1;i<=len;i++)
    {
        int c=s[i];
        if(!t[p][c])
        {
            return ans;
        }
        p=t[p][c];
        ans+=cnt1[p];
    }
    return ans-cnt1[p]+cnt[p];
}
int main()
{
    int m,n;
    scanf("%d%d",&m,&n);
    for(int i=1;i<=m;i++)
    {
        int b;
        scanf("%d",&b);
        for(int j=1;j<=b;j++)
        {
            scanf("%d",&s[j]);
        }
        insert(s,b);
    }
    for(int i=1;i<=n;i++)
    {
        int c;
        scanf("%d",&c);
        for(int j=1;j<=c;j++)
        {
            scanf("%d",&s[j]);
        }
        printf("%d\n",query(s,c));
    }
    return 0;
}
